    15→public interface ZipOutputStreamRefinements {
    16→
    17→    @StateRefinement(to = "open(this)")
    18→    public void ZipOutputStream(OutputStream out);
    19→
    20→    @StateRefinement(to = "open(this)")
    21→    public void ZipOutputStream(OutputStream out, Charset charset);
    22→
    23→    @StateRefinement(to = "closed(this)")
    24→    public void close();
    25→
    26→    @StateRefinement(from = "entryopen(this)", to = "open(this)")
    27→    public void closeEntry();
    28→
    29→    @StateRefinement(from = "open(this)", to = "finished(this)")
    30→    @StateRefinement(from = "entryopen(this)", to = "finished(this)")
    31→    public void finish();
    32→
    33→    @StateRefinement(from = "open(this)", to = "entryopen(this)")
    34→    @StateRefinement(from = "entryopen(this)")
    35→    public void putNextEntry(ZipEntry e);
    36→
    37→    @StateRefinement(from = "open(this)")
    38→    @StateRefinement(from = "entryopen(this)")
    39→    public void setComment(String comment);
    40→
    41→    @StateRefinement(from = "open(this)")
    42→    @StateRefinement(from = "entryopen(this)")
    43→    public void setLevel(@Refinement("ValidLevel(level)") int level);
    44→
    45→    @StateRefinement(from = "open(this)")
    46→    @StateRefinement(from = "entryopen(this)")
    47→    public void setMethod(@Refinement("method == 0 || method == 8") int method);
    48→
    49→    @StateRefinement(from = "entryopen(this)")
    50→    public void write(byte[] b, @Refinement("off >= 0") int off, @Refinement("len >= 0 && len <= b.length - off") int len);
    51→
    52→}
